input.command:
node --input-type=module -e "
import fs from 'fs';
const data = JSON.parse(fs.readFileSync('/workspace/group/links-raw.json', 'utf8'));
// Filter last 6 months: from 2025-09-28 to 2026-03-28
// And Twitter/X platform
const cutoff = new Date('2025-09-28');
const tweets = data.filter(l => {
  const d = new Date(l.date);
  return d >= cutoff && (l.platform === 'Twitter/X' || l.url?.includes('twitter.com') || l.url?.includes('x.com'));
});
console.log(JSON.stringify(tweets, null, 2));
"
